import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { useSelector } from 'react-redux';
import { dashboardAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';

const MOCK_DATA = {
  stats: { total_students:1248, total_employees:87, todayAttendancePercent:94.2, todayCollection:120000, open_enquiries:12 },
  notices: [
    { id:1, title:'Parent-Teacher Meeting on 12 June 2025', notice_type:'event', publish_date:'2025-06-05', posted_by:'Principal' },
    { id:2, title:'Half-Yearly Exam Schedule Released', notice_type:'circular', publish_date:'2025-06-03', posted_by:'Academic Dept' },
    { id:3, title:'Annual Day Preparations Begin', notice_type:'event', publish_date:'2025-06-01', posted_by:'Event Committee' },
  ],
  recentAdmissions: [
    { id:1, first_name:'Ravi', last_name:'Gupta',   class_name:'Class 6', section_name:'A', admission_date:'2025-06-06' },
    { id:2, first_name:'Sneha', last_name:'Patel',  class_name:'Class 9', section_name:'A', admission_date:'2025-06-05' },
    { id:3, first_name:'Mohit', last_name:'Singh',  class_name:'Class 11',section_name:'',  admission_date:'2025-06-04' },
    { id:4, first_name:'Anita', last_name:'Rao',    class_name:'Class 7', section_name:'B', admission_date:'2025-06-03' },
  ],
  classWiseFees: [
    { class_name:'Class 6',  collected:76,  pending:24 },
    { class_name:'Class 7',  collected:88,  pending:12 },
    { class_name:'Class 8',  collected:92,  pending:8  },
    { class_name:'Class 9',  collected:71,  pending:29 },
    { class_name:'Class 10', collected:95,  pending:5  },
    { class_name:'Class 11', collected:68,  pending:32 },
    { class_name:'Class 12', collected:84,  pending:16 },
  ],
  birthdays: [
    { id:1, first_name:'Priya',  last_name:'Sharma', class_name:'8A', date:'Today' },
    { id:2, first_name:'Arjun',  last_name:'Verma',  class_name:'10B',date:'Tomorrow' },
  ],
};

const STAT_CARDS = [
  { key:'total_students',          label:'Total Students',     icon:'🎓', color:'#7C3AED', bg:'#EDE9FE', page:'/students',  fmt: v => v.toLocaleString() },
  { key:'total_employees',         label:'Employees',          icon:'👥', color:'#059669', bg:'#D1FAE5', page:'/employees', fmt: v => v },
  { key:'todayAttendancePercent',  label:"Today's Attendance", icon:'✅', color:'#D97706', bg:'#FEF3C7', page:'/attendance',fmt: v => `${v}%` },
  { key:'todayCollection',         label:"Today's Collection", icon:'💰', color:'#DC2626', bg:'#FEE2E2', page:'/fees',      fmt: v => `₹${(v/1000).toFixed(0)}K` },
];

export default function Dashboard() {
  const user = useSelector(s => s.auth.user);
  const navigate = useNavigate();

  const { data: apiData, isError } = useQuery({
    queryKey: ['dashboard'],
    queryFn: () => dashboardAPI.get().then(r => r.data.data),
    retry: 1,
    staleTime: 30000,
  });

  const data = (isError || !apiData) ? MOCK_DATA : apiData;
  const stats = data?.stats || {};
  const isMock = isError || !apiData;

  const greeting = () => {
    const h = new Date().getHours();
    if (h < 12) return 'Good morning';
    if (h < 17) return 'Good afternoon';
    return 'Good evening';
  };

  return (
    <div>
      {/* Header */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:20, flexWrap:'wrap', gap:12 }}>
        <div>
          <h1 style={{ fontSize:20, fontWeight:700, color:'#111827' }}>
            {greeting()}, {user?.full_name?.split(' ')[0] || 'Principal'} 👋
          </h1>
          <p style={{ fontSize:12, color:'#6B7280', marginTop:3 }}>
            Academic Year 2025–26 · {new Date().toDateString()} · Sunrise High School
          </p>
        </div>
        <div style={{ display:'flex', gap:10 }}>
          <button onClick={() => navigate('/fees')}
            style={{ padding:'8px 14px', background:'#fff', border:'1px solid #E5E7EB', borderRadius:8, fontSize:12, fontWeight:600, color:'#374151', cursor:'pointer' }}>
            📢 Post Notice
          </button>
          <button onClick={() => navigate('/students')}
            style={{ padding:'8px 14px', background:'#1E1B4B', color:'#fff', border:'none', borderRadius:8, fontSize:12, fontWeight:600, cursor:'pointer' }}>
            + New Admission
          </button>
        </div>
      </div>

      {/* Mock mode banner */}
      {isMock && (
        <div style={{ padding:'10px 14px', background:'#FEF3C7', border:'1px solid #FCD34D', borderRadius:10, marginBottom:16, fontSize:12, color:'#92400E', display:'flex', alignItems:'center', gap:8 }}>
          <span>⚡</span>
          <span><strong>Demo Mode:</strong> Showing sample data. Start the backend (port 5000) + run seed to see live data.</span>
        </div>
      )}

      {/* Stat Cards */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, marginBottom:20 }}>
        {STAT_CARDS.map(c => (
          <div key={c.key} onClick={() => navigate(c.page)}
            style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, padding:16, cursor:'pointer', transition:'all .18s' }}
            onMouseEnter={e => { e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 8px 20px rgba(0,0,0,.08)'; }}
            onMouseLeave={e => { e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow=''; }}>
            <div style={{ width:38, height:38, borderRadius:10, background:c.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:18, marginBottom:12 }}>{c.icon}</div>
            <div style={{ fontSize:24, fontWeight:700, color:c.color, lineHeight:1, marginBottom:4 }}>
              {c.fmt(stats[c.key] || 0)}
            </div>
            <div style={{ fontSize:11, color:'#6B7280' }}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* Second row stats */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, marginBottom:20 }}>
        {[
          { label:'New Admissions', value:28, icon:'📋', sub:'↑ 8 this week',   color:'#2D1B69' },
          { label:'Open Enquiries', value:stats.open_enquiries||12, icon:'📞', sub:'4 follow-ups due', color:'#0891B2' },
          { label:'Books Overdue',  value:24, icon:'📚', sub:'↑ 3 this week',   color:'#D97706' },
          { label:'Active Routes',  value:4,  icon:'🚌', sub:'248 students',    color:'#059669' },
        ].map(c => (
          <div key={c.label} style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, padding:16 }}>
            <div style={{ fontSize:20, marginBottom:8 }}>{c.icon}</div>
            <div style={{ fontSize:22, fontWeight:700, color:c.color, lineHeight:1, marginBottom:4 }}>{c.value}</div>
            <div style={{ fontSize:11, color:'#6B7280' }}>{c.label}</div>
            <div style={{ fontSize:10, color:'#10B981', marginTop:4, fontWeight:600 }}>{c.sub}</div>
          </div>
        ))}
      </div>

      {/* Main grid */}
      <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr', gap:16, marginBottom:16 }}>
        {/* Income/Expense Chart */}
        <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, overflow:'hidden' }}>
          <div style={{ padding:'14px 18px', borderBottom:'0.5px solid #F3F4F6', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <span style={{ fontSize:13, fontWeight:700 }}>📊 Income vs Expense — 2025–26</span>
            <div style={{ display:'flex', gap:12, fontSize:11, color:'#6B7280' }}>
              <span style={{ display:'flex', alignItems:'center', gap:4 }}><span style={{ width:10, height:10, background:'#1E1B4B', borderRadius:2, display:'inline-block' }}/> Income</span>
              <span style={{ display:'flex', alignItems:'center', gap:4 }}><span style={{ width:10, height:10, background:'#EF4444', borderRadius:2, display:'inline-block', opacity:.7 }}/> Expense</span>
            </div>
          </div>
          <div style={{ padding:'16px 20px 12px' }}>
            <svg width="100%" viewBox="0 0 440 150" style={{ overflow:'visible' }}>
              {[10,45,80,115].map(y => <line key={y} x1="30" y1={y} x2="440" y2={y} stroke="#F3F4F6" strokeWidth="0.5"/>)}
              {['₹35L','₹26L','₹17L','₹8L'].map((l,i) => <text key={l} x="0" y={10+i*35+4} fontSize="8" fill="#9CA3AF">{l}</text>)}
              {[
                [40,40,90],[100,22,110],[160,32,95],[220,58,65],[280,18,120],[340,28,105],[400,48,80]
              ].map(([x,y,h],i) => <g key={i}>
                <rect x={x} y={y} width="22" height={h} rx="4" fill="#1E1B4B" opacity=".9"/>
                <rect x={x+25} y={y+20} width="16" height={h-20} rx="3" fill="#EF4444" opacity=".7"/>
              </g>)}
              {['Apr','May','Jun','Jul','Aug','Sep','Oct'].map((m,i) => <text key={m} x={51+i*60} y="140" fontSize="9" fill="#9CA3AF" textAnchor="middle">{m}</text>)}
            </svg>
          </div>
        </div>

        {/* Notices + Birthdays */}
        <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
          <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, flex:1 }}>
            <div style={{ padding:'12px 16px', borderBottom:'0.5px solid #F3F4F6', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <span style={{ fontSize:13, fontWeight:700 }}>📢 Notices</span>
              <button onClick={() => navigate('/notices')} style={{ fontSize:11, color:'#6B52B0', background:'none', border:'none', cursor:'pointer', fontWeight:600 }}>View all →</button>
            </div>
            <div style={{ padding:'8px 16px' }}>
              {(data?.notices || []).map(n => (
                <div key={n.id} style={{ padding:'8px 0', borderBottom:'0.5px solid #F9FAFB', display:'flex', gap:10, alignItems:'flex-start' }}>
                  <div style={{ width:6, height:6, borderRadius:'50%', background:'#7C3AED', flexShrink:0, marginTop:5 }}/>
                  <div>
                    <div style={{ fontSize:12, fontWeight:600, lineHeight:1.4 }}>{n.title}</div>
                    <div style={{ fontSize:10, color:'#9CA3AF', marginTop:2 }}>{n.posted_by} · {new Date(n.publish_date).toLocaleDateString('en-IN')}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14 }}>
            <div style={{ padding:'12px 16px', borderBottom:'0.5px solid #F3F4F6' }}>
              <span style={{ fontSize:13, fontWeight:700 }}>🎂 Birthdays</span>
            </div>
            <div style={{ padding:'8px 16px' }}>
              {(data?.birthdays || []).map(b => (
                <div key={b.id} style={{ padding:'7px 0', display:'flex', alignItems:'center', gap:10, borderBottom:'0.5px solid #F9FAFB' }}>
                  <div style={{ width:30, height:30, borderRadius:8, background:'#EDE9F8', display:'flex', alignItems:'center', justifyContent:'center', fontSize:14 }}>🎂</div>
                  <div>
                    <div style={{ fontSize:12, fontWeight:600 }}>{b.first_name} {b.last_name} <span style={{ padding:'1px 6px', borderRadius:10, fontSize:9, background:'#EDE9F8', color:'#1E1B4B', fontWeight:700 }}>{b.class_name}</span></div>
                    <div style={{ fontSize:10, color:'#9CA3AF', marginTop:1 }}>{b.date}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Bottom row */}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
        {/* Recent Admissions */}
        <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, overflow:'hidden' }}>
          <div style={{ padding:'12px 16px', borderBottom:'0.5px solid #F3F4F6', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <span style={{ fontSize:13, fontWeight:700 }}>🆕 Recent Admissions</span>
            <button onClick={() => navigate('/students')} style={{ fontSize:11, color:'#6B52B0', background:'none', border:'none', cursor:'pointer', fontWeight:600 }}>View all →</button>
          </div>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead><tr style={{ background:'#F9FAFB' }}>
              {['Student','Class','Date','Status'].map(h => <th key={h} style={{ padding:'8px 12px', textAlign:'left', color:'#6B7280', fontSize:10, fontWeight:600, textTransform:'uppercase' }}>{h}</th>)}
            </tr></thead>
            <tbody>
              {(data?.recentAdmissions || []).map(s => (
                <tr key={s.id} style={{ borderBottom:'0.5px solid #F3F4F6' }}>
                  <td style={{ padding:'9px 12px', fontWeight:600 }}>{s.first_name} {s.last_name}</td>
                  <td style={{ padding:'9px 12px', color:'#6B7280' }}>{s.class_name} {s.section_name}</td>
                  <td style={{ padding:'9px 12px', color:'#9CA3AF', fontSize:11 }}>{new Date(s.admission_date).toLocaleDateString('en-IN')}</td>
                  <td style={{ padding:'9px 12px' }}><span style={{ padding:'2px 8px', borderRadius:20, fontSize:10, background:'#D1FAE5', color:'#065F46' }}>Active</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* Quick Actions */}
        <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14 }}>
          <div style={{ padding:'12px 16px', borderBottom:'0.5px solid #F3F4F6' }}>
            <span style={{ fontSize:13, fontWeight:700 }}>⚡ Quick Actions</span>
          </div>
          <div style={{ padding:16 }}>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:10 }}>
              {[
                ['📋','New Admission','/students'],['💰','Collect Fee','/fees'],
                ['✅','Attendance','/attendance'],['📢','Notice','/notices'],
                ['👤','Add Staff','/employees'],['📊','Reports','/reports'],
                ['🚌','Transport','/'],['📜','Certificates','/'],
              ].map(([icon,label,path]) => (
                <div key={label} onClick={() => navigate(path)}
                  style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:6, padding:'12px 6px', background:'#F9FAFB', border:'0.5px solid #E5E7EB', borderRadius:12, cursor:'pointer', transition:'all .15s', textAlign:'center' }}
                  onMouseEnter={e => { e.currentTarget.style.background='#EDE9F8'; e.currentTarget.style.borderColor='#A78BFA'; }}
                  onMouseLeave={e => { e.currentTarget.style.background='#F9FAFB'; e.currentTarget.style.borderColor='#E5E7EB'; }}>
                  <span style={{ fontSize:22 }}>{icon}</span>
                  <span style={{ fontSize:10, fontWeight:600, color:'#4B5563', lineHeight:1.3 }}>{label}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Class-wise Fee Bar Chart */}
      <div style={{ background:'#fff', border:'0.5px solid #E5E7EB', borderRadius:14, marginTop:16 }}>
        <div style={{ padding:'12px 16px', borderBottom:'0.5px solid #F3F4F6', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <span style={{ fontSize:13, fontWeight:700 }}>📊 Class-wise Fee Collection</span>
          <button onClick={() => navigate('/fees')} style={{ fontSize:11, color:'#6B52B0', background:'none', border:'none', cursor:'pointer', fontWeight:600 }}>Full report →</button>
        </div>
        <div style={{ padding:'16px 20px' }}>
          {(data?.classWiseFees || []).map(c => (
            <div key={c.class_name} style={{ display:'flex', alignItems:'center', gap:10, marginBottom:10 }}>
              <span style={{ fontSize:11, color:'#6B7280', width:70, textAlign:'right', flexShrink:0 }}>{c.class_name}</span>
              <div style={{ flex:1, height:16, background:'#F3F4F6', borderRadius:8, overflow:'hidden', position:'relative' }}>
                <div style={{ position:'absolute', top:0, left:0, width:`${c.collected}%`, height:'100%', background:'#1E1B4B', borderRadius:'8px 0 0 8px', transition:'width 1s' }}/>
                <div style={{ position:'absolute', top:0, left:`${c.collected}%`, width:`${c.pending}%`, height:'100%', background:'#FCA5A5', borderRadius:'0 8px 8px 0' }}/>
              </div>
              <span style={{ fontSize:11, fontWeight:700, color:'#1E1B4B', width:36, flexShrink:0, textAlign:'right' }}>{c.collected}%</span>
            </div>
          ))}
          <div style={{ display:'flex', gap:16, marginTop:12, fontSize:11, color:'#6B7280' }}>
            <span style={{ display:'flex', alignItems:'center', gap:5 }}><span style={{ width:10, height:10, background:'#1E1B4B', borderRadius:2, display:'inline-block' }}/> Collected</span>
            <span style={{ display:'flex', alignItems:'center', gap:5 }}><span style={{ width:10, height:10, background:'#FCA5A5', borderRadius:2, display:'inline-block' }}/> Pending</span>
          </div>
        </div>
      </div>
    </div>
  );
}
